// D20 Die — deep midnight blue body with gold raised 7-segment numbers
// Numbers are a SEPARATE label/color from the die body.
const { Manifold, CrossSection } = api;

// ============================================================================
// 1. Icosahedron body
// ============================================================================
const phi = (1 + Math.sqrt(5)) / 2;
const R = 9; // circumradius
const rawVerts = [
  [0, 1, phi], [0, -1, phi], [0, 1, -phi], [0, -1, -phi],
  [1, phi, 0], [-1, phi, 0], [1, -phi, 0], [-1, -phi, 0],
  [phi, 0, 1], [-phi, 0, 1], [phi, 0, -1], [-phi, 0, -1],
];
const sc = R / Math.sqrt(1 + phi * phi);
const V = rawVerts.map(([x, y, z]) => [x * sc, y * sc, z * sc]);

const body = Manifold.hull(V.map(v => Manifold.sphere(0.35, 4).translate(v)));

// ============================================================================
// 2. Math helpers
// ============================================================================
const sub  = (a, b) => [a[0]-b[0], a[1]-b[1], a[2]-b[2]];
const dot  = (a, b) =>  a[0]*b[0] + a[1]*b[1] + a[2]*b[2];
const cross = (a, b) => [
  a[1]*b[2] - a[2]*b[1],
  a[2]*b[0] - a[0]*b[2],
  a[0]*b[1] - a[1]*b[0],
];
const norm = a => { const m = Math.hypot(a[0], a[1], a[2]); return [a[0]/m, a[1]/m, a[2]/m]; };
const RAD  = 180 / Math.PI;
const rotY = t => [
  [Math.cos(t),  0, Math.sin(t)],
  [0,            1, 0           ],
  [-Math.sin(t), 0, Math.cos(t) ],
];
const rotZ = t => [
  [Math.cos(t), -Math.sin(t), 0],
  [Math.sin(t),  Math.cos(t), 0],
  [0,            0,           1],
];
const mv = (M, v) => [
  M[0][0]*v[0] + M[0][1]*v[1] + M[0][2]*v[2],
  M[1][0]*v[0] + M[1][1]*v[1] + M[1][2]*v[2],
  M[2][0]*v[0] + M[2][1]*v[1] + M[2][2]*v[2],
];

// ============================================================================
// 3. Enumerate the 20 triangular faces
// ============================================================================
const dist = (a, b) => Math.hypot(a[0]-b[0], a[1]-b[1], a[2]-b[2]);
let edge = Infinity;
for (let i = 0; i < 12; i++)
  for (let j = i+1; j < 12; j++) edge = Math.min(edge, dist(V[i], V[j]));
const isEdge = (a, b) => Math.abs(dist(V[a], V[b]) - edge) < 1e-6 * R;

const faces = [];
for (let a = 0; a < 12; a++)
  for (let b = a+1; b < 12; b++)
    for (let c = b+1; c < 12; c++)
      if (isEdge(a,b) && isEdge(b,c) && isEdge(a,c)) faces.push([a,b,c]);

function faceInfo(tri) {
  const c = [0,0,0];
  for (const idx of tri) for (let k=0;k<3;k++) c[k] += V[idx][k]/3;
  const n = norm(c);
  let ref = [0, 0, 1];
  let up = sub(ref, [n[0]*dot(ref,n), n[1]*dot(ref,n), n[2]*dot(ref,n)]);
  if (Math.hypot(up[0],up[1],up[2]) < 1e-3) {
    ref = [0, 1, 0];
    up = sub(ref, [n[0]*dot(ref,n), n[1]*dot(ref,n), n[2]*dot(ref,n)]);
  }
  up = norm(up);
  return { centroid: c, normal: n, up };
}
const info = faces.map(faceInfo);

// ============================================================================
// 4. 7-segment numeral builder — extruded Manifold (raised by LIFT above face)
// ============================================================================
const Wc = 1.7, Hc = 2.8, t = 0.5;
const LIFT = 0.5;   // how far numbers rise above face surface
const EXT  = 0.7;   // extrusion depth (into body + proud)

const SEG = {
  A: [0, Hc-t, Wc, Hc],
  G: [0, Hc/2-t/2, Wc, Hc/2+t/2],
  D: [0, 0, Wc, t],
  F: [0, Hc/2, t, Hc],
  B: [Wc-t, Hc/2, Wc, Hc],
  E: [0, 0, t, Hc/2],
  C: [Wc-t, 0, Wc, Hc/2],
};
const DIGITS = {
  '0': ['A','B','C','D','E','F'],
  '1': ['B','C'],
  '2': ['A','B','G','E','D'],
  '3': ['A','B','G','C','D'],
  '4': ['F','G','B','C'],
  '5': ['A','F','G','C','D'],
  '6': ['A','F','G','E','C','D'],
  '7': ['A','B','C'],
  '8': ['A','B','C','D','E','F','G'],
  '9': ['A','B','C','D','F','G'],
};

function digitCS(ch) {
  const bars = DIGITS[ch].map(name => {
    const [x0, y0, x1, y1] = SEG[name];
    return CrossSection.square([x1-x0, y1-y0]).translate([x0, y0]);
  });
  return CrossSection.union(bars).translate([-Wc/2, -Hc/2]);
}

function numberCS(str) {
  const gap = 0.4;
  const totalW = str.length * Wc + (str.length-1) * gap;
  let x = -totalW/2 + Wc/2;
  const parts = [];
  for (const ch of str) {
    parts.push(digitCS(ch).translate([x, 0]));
    x += Wc + gap;
  }
  return CrossSection.union(parts);
}

// Extrude a 2D numeral cross section into a 3D solid (Z direction = face normal)
// z range: [-0.2, EXT] so it bites slightly into die and protrudes by LIFT
function extrudeNumber(str) {
  const cs = numberCS(str);
  // Extrude from slightly below surface to above surface
  return Manifold.extrude(cs, EXT + 0.2).translate([0, 0, -0.2]);
}

// ============================================================================
// 5. Orient a flat (+Z) glyph onto a face
// ============================================================================
function buildOriented(flat, fi) {
  const n = fi.normal;
  const theta = Math.acos(Math.max(-1, Math.min(1, n[2])));
  const azim  = Math.atan2(n[1], n[0]);
  const base  = v => mv(rotZ(azim), mv(rotY(theta), v));
  const baseUp = base([0, 1, 0]);
  const cosA  = Math.max(-1, Math.min(1, dot(baseUp, fi.up)));
  let spin = Math.acos(cosA);
  if (dot(cross(baseUp, fi.up), n) < 0) spin = -spin;
  return flat
    .rotate([0, 0,         spin  * RAD])
    .rotate([0, theta * RAD, 0        ])
    .rotate([0, 0,         azim  * RAD]);
}

// ============================================================================
// 6. Standard d20 numbering — opposite faces sum to 21
// ============================================================================
const used       = new Array(20).fill(false);
const faceNumber = new Array(20).fill(0);
let k = 1;
for (let i = 0; i < 20; i++) {
  if (used[i]) continue;
  let opp = -1;
  for (let j = 0; j < 20; j++) {
    if (j === i || used[j]) continue;
    if (dot(info[i].normal, info[j].normal) < -0.999) { opp = j; break; }
  }
  used[i] = true;
  faceNumber[i] = k;
  if (opp >= 0) { used[opp] = true; faceNumber[opp] = 21-k; }
  k++;
}

// ============================================================================
// 7. Build raised number solids, placed on each face
// ============================================================================
const numberParts = [];
for (let i = 0; i < 20; i++) {
  const fi   = info[i];
  const flat = extrudeNumber(String(faceNumber[i]));
  const oriented = buildOriented(flat, fi);
  // Translate to face centroid (the centroid is ON the face surface).
  // The extrusion goes from -0.2 (inside die) to EXT (outside die),
  // but we push it outward by LIFT so the top of the glyph is LIFT above surface.
  const push = fi.normal.map(c => c * (LIFT - EXT));
  numberParts.push(oriented.translate([
    fi.centroid[0] + push[0],
    fi.centroid[1] + push[1],
    fi.centroid[2] + push[2],
  ]));
}

const allNumbers = Manifold.union(numberParts);

// ============================================================================
// 8. Label body and numbers separately, then union them into one solid
// ============================================================================
// The union fuses body+numbers into one manifold piece.
// api.label assigns colors to each labeled region independently.
const labeledBody    = api.label(body,       'die',     { color: '#0d1b4e' });
const labeledNumbers = api.label(allNumbers, 'numbers', { color: '#f0d080' });

return labeledBody.add(labeledNumbers);
